// แนวคิดพื้นฐาน AJAX
// 1. เกิด Event บนเว็บ (click, load, scroll)
// 2. สร้าง XMLHttpRequest/fetch
// 3. ส่ง Request ไปยัง Server
// 4. Server ประมวลผล
// 5. Server ส่ง Response กลับ
// 6. JavaScript รับ Response
// 7. อัปเดต UI โดยไม่ reload

// GET Request พื้นฐาน
$.ajax({
  url: 'https://api.example.com/users',
  type: 'GET',
  dataType: 'json',
  success: function(data) {
    console.log('ได้ข้อมูลแล้ว:', data);
    // อัปเดต UI
    $.each(data, function(index, user) {
      $('#userList').append(
        '<li>' + user.name + '</li>'
      );
    });
  },
  error: function(xhr, status, error) {
    console.error('เกิดข้อผิดพลาด:', error);
  }
});

// POST Request — ส่งข้อมูลไป Server
$.ajax({
  url: 'https://api.example.com/users',
  type: 'POST',
  contentType: 'application/json',
  data: JSON.stringify({
    name: 'สมชาย',
    email: 'somchai@email.com',
    role: 'developer'
  }),
  success: function(response) {
    console.log('สร้างสำเร็จ:', response);
    // แสดงข้อความสำเร็จ
    $('#status').text('✅ บันทึกข้อมูลสำเร็จ!');
  },
  error: function(xhr, status, error) {
    $('#status').text('❌ เกิดข้อผิดพลาด: ' + error);
  }
});

// $.get() — GET แบบสั้น
$.get('https://api.example.com/data', function(data) {
  console.log(data);
});

// $.post() — POST แบบสั้น
$.post('https://api.example.com/data', 
  { name: 'jQuery', type: 'library' },
  function(response) {
    console.log(response);
  }
);

// $.getJSON() — GET เฉพาะ JSON
$.getJSON('data/info.json', function(json) {
  console.log(json);
});

// .load() — โหลด HTML ใส่ element
$('#content').load('pages/about.html');

// Callback แบบดั้งเดิม
$.ajax({
  url: '/api/data',
  success: function(data) { /* สำเร็จ */ },
  error: function(err) { /* ผิดพลาด */ },
  complete: function() { /* ทำเสมอ */ }
});

// Promise / Deferred Pattern
$.ajax({ url: '/api/data' })
  .done(function(data) {
    console.log('สำเร็จ:', data);
  })
  .fail(function(err) {
    console.log('ผิดพลาด:', err);
  })
  .always(function() {
    console.log('Request เสร็จสิ้น');
    $('#loader').hide();
  });

// แสดง Loading ทุกครั้งที่มี AJAX request
$(document)
  .ajaxStart(function() {
    $('#loading-spinner').fadeIn(200);
  })
  .ajaxStop(function() {
    $('#loading-spinner').fadeOut(200);
  })
  .ajaxError(function(event, xhr, settings) {
    console.error('AJAX Error:', settings.url);
    $('#error-toast').text('เกิดข้อผิดพลาด!')
                     .fadeIn().delay(3000).fadeOut();
  });

// ตั้งค่า Default สำหรับทุก AJAX request
$.ajaxSetup({
  timeout: 5000,
  headers: {
    'Authorization': 'Bearer ' + token
  }
});
